467	func localOverlayPaths(pluginName string, files []string) []string {
468		seen := map[string]bool{}
469		add := func(path string) {
470			path = filepath.ToSlash(strings.TrimSpace(path))
471			path = strings.TrimPrefix(path, "./")
472			if path == "" || strings.HasPrefix(path, "~") || filepath.IsAbs(path) {
473				return
474			}
475			if !seen[path] {
476				seen[path] = true
477			}
478		}
479	
480		add(filepath.ToSlash(ddxroot.JoinRelative("plugins", pluginName)))
481		for _, file := range files {
482			p := filepath.ToSlash(file)
483			for _, prefix := range []string{".agents/skills/", ".claude/skills/"} {
484				if strings.HasPrefix(p, prefix) {
485					rest := strings.TrimPrefix(p, prefix)
486					name := strings.Split(rest, "/")[0]
487					if name != "" {
488						add(prefix + name)
489					}
490				}
491			}
492		}
493	
494		paths := make([]string, 0, len(seen))
495		for p := range seen {
496			paths = append(paths, p)
497		}
498		sort.Strings(paths)
499		return paths
500	}
