168	func parseRemoteProject(remoteURL string) (string, bool) {
169		remoteURL = strings.TrimSpace(remoteURL)
170		if remoteURL == "" {
171			return "", false
172		}
173		if host, repoPath, ok := parseSCPLikeRemote(remoteURL); ok {
174			return filepath.Join(host, repoPath), true
175		}
176		u, err := url.Parse(remoteURL)
177		if err != nil || u.Host == "" {
178			return "", false
179		}
180		repoPath := normalizeRepoPath(u.Path)
181		if repoPath == "" {
182			return "", false
183		}
184		return filepath.Join(u.Host, repoPath), true
185	}
186	
187	func parseSCPLikeRemote(remoteURL string) (host, repoPath string, ok bool) {
188		if strings.Contains(remoteURL, "://") {
189			return "", "", false
190		}
191		at := strings.IndexByte(remoteURL, '@')
192		colon := strings.IndexByte(remoteURL, ':')
193		if at <= 0 || colon <= at+1 {
194			return "", "", false
195		}
196		host = strings.TrimSpace(remoteURL[at+1 : colon])
197		repoPath = normalizeRepoPath(remoteURL[colon+1:])
198		if host == "" || repoPath == "" {
199			return "", "", false
200		}
201		return host, repoPath, true
202	}
203	
204	func normalizeRepoPath(raw string) string {
205		raw = strings.TrimSpace(raw)
206		raw = strings.Trim(raw, "/")
207		raw = strings.TrimSuffix(raw, ".git")
208		if raw == "" {
209			return ""
210		}
211		parts := strings.FieldsFunc(raw, func(r rune) bool {
212			return r == '/' || r == '\\'
213		})
214		if len(parts) == 0 {
215			return ""
216		}
217		return filepath.Join(parts...)
218	}
219	
220	func localProjectIdentity(projectRoot string) string {
221		absRoot, err := filepath.Abs(projectRoot)
222		if err != nil {
223			absRoot = filepath.Clean(projectRoot)
224		}
225		base := filepath.Base(absRoot)
226		if base == "." || base == string(filepath.Separator) || base == "" {
227			base = "project"
228		}
229		return filepath.Join("local", base+"-"+shortPathHash(absRoot))
230	}
231	
232	func shortPathHash(path string) string {
233		sum := sha1.Sum([]byte(path))
234		return hex.EncodeToString(sum[:])[:8]
235	}
