237	const bootstrapCommitMessage = "chore: bootstrap ddx state"
238	
239	var bootstrapLockStaleAge = 2 * time.Minute
240	
241	type worktreeRegistry struct {
242		Paths  []worktreeRegistryEntry `json:"paths"`
243		Master string                  `json:"master"`
244	}
245	
246	type worktreeRegistryEntry struct {
247		Path        string `json:"path"`
248		FirstSeenAt string `json:"first_seen_at"`
249		LastSeenAt  string `json:"last_seen_at"`
250		Hostname    string `json:"hostname"`
251	}
252	
253	func bootstrapConventionRoot(ctx context.Context, projectRoot, root string) error {
254		if ctx == nil {
255			ctx = context.Background()
256		}
257		return withBootstrapLock(root, func() error {
258			if err := os.MkdirAll(root, 0o755); err != nil {
259				return err
260			}
261			if err := ensureGitRepo(ctx, root); err != nil {
262				return err
263			}
264			changed, err := ensureWorktreeRegistry(projectRoot, root)
265			if err != nil {
266				return err
267			}
268			if err := ensureHeadCommit(ctx, root, changed); err != nil {
269				return err
270			}
271			return nil
272		})
273	}
274	
275	func withBootstrapLock(root string, fn func() error) error {
276		lockDir := root + ".bootstrap.lock"
277		if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
278			return err
279		}
280		deadline := time.Now().Add(30 * time.Second)
281		for {
282			err := os.Mkdir(lockDir, 0o755)
283			if err == nil {
284				_ = os.WriteFile(filepath.Join(lockDir, "pid"), []byte(strconv.Itoa(os.Getpid())), 0o644)
285				_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(time.Now().UTC().Format(time.RFC3339Nano)), 0o644)
286				defer os.RemoveAll(lockDir)
287				return fn()
288			}
289			if breakStaleBootstrapLock(lockDir) {
290				continue
291			}
292			if time.Now().After(deadline) {
293				return err
294			}
295			time.Sleep(25 * time.Millisecond)
296		}
297	}
298	
299	func breakStaleBootstrapLock(lockDir string) bool {
300		acquiredAt, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
301		if err == nil {
302			if ts, parseErr := time.Parse(time.RFC3339Nano, strings.TrimSpace(string(acquiredAt))); parseErr == nil && time.Since(ts) > bootstrapLockStaleAge {
303				_ = os.RemoveAll(lockDir)
304				return true
305			}
306		}
307		return false
308	}
309	
310	func ensureGitRepo(ctx context.Context, root string) error {
311		if out, err := gitpkg.Command(ctx, root, "rev-parse", "--git-dir").CombinedOutput(); err == nil {
312			_ = out
313			return nil
314		}
315		out, err := gitpkg.Command(ctx, root, "init").CombinedOutput()
316		if err != nil {
317			return newGitError("git init", out, err)
318		}
319		return nil
320	}
321	
322	func ensureWorktreeRegistry(projectRoot, root string) (bool, error) {
323		worktreePath, err := canonicalWorktreePath(projectRoot)
324		if err != nil {
325			return false, err
326		}
327	
328		registryPath := filepath.Join(root, "worktrees.json")
329		registry, err := readWorktreeRegistry(registryPath)
330		if err != nil {
331			return false, err
332		}
333	
334		now := time.Now().UTC().Format(time.RFC3339Nano)
335		hostname, err := os.Hostname()
336		if err != nil || strings.TrimSpace(hostname) == "" {
337			hostname = "unknown"
338		}
339	
340		changed := upsertWorktreeRegistryEntry(&registry, worktreePath, now, hostname)
341		if registry.Master == "" {
342			registry.Master = worktreePath
343			changed = true
344		}
345		if !changed {
346			return false, nil
347		}
348		return true, writeWorktreeRegistry(registryPath, registry)
349	}
350	
351	func upsertWorktreeRegistryEntry(registry *worktreeRegistry, worktreePath, now, hostname string) bool {
352		for i := range registry.Paths {
353			if registry.Paths[i].Path != worktreePath {
354				continue
355			}
356			changed := false
357			if registry.Paths[i].FirstSeenAt == "" {
358				registry.Paths[i].FirstSeenAt = now
359				changed = true
360			}
361			if registry.Paths[i].LastSeenAt != now {
362				if registry.Paths[i].LastSeenAt == "" {
363					registry.Paths[i].LastSeenAt = registry.Paths[i].FirstSeenAt
364				}
365				if registry.Paths[i].LastSeenAt != now {
366					registry.Paths[i].LastSeenAt = now
367				}
368				changed = true
369			}
370			if registry.Paths[i].Hostname == "" {
371				registry.Paths[i].Hostname = hostname
372				changed = true
373			}
374			return changed
375		}
376	
377		registry.Paths = append(registry.Paths, worktreeRegistryEntry{
378			Path:        worktreePath,
379			FirstSeenAt: now,
380			LastSeenAt:  now,
381			Hostname:    hostname,
382		})
383		return true
384	}
385	
386	func canonicalWorktreePath(projectRoot string) (string, error) {
387		abs, err := filepath.Abs(projectRoot)
388		if err != nil {
389			return "", err
390		}
391		return filepath.Clean(abs), nil
392	}
393	
394	func readWorktreeRegistry(path string) (worktreeRegistry, error) {
395		data, err := os.ReadFile(path)
396		if err != nil {
397			if os.IsNotExist(err) {
398				return worktreeRegistry{}, nil
399			}
400			return worktreeRegistry{}, err
401		}
402		if len(data) == 0 {
403			return worktreeRegistry{}, nil
404		}
405		var registry worktreeRegistry
406		if err := json.Unmarshal(data, &registry); err != nil {
407			return worktreeRegistry{}, err
408		}
409		return registry, nil
410	}
411	
412	func writeWorktreeRegistry(path string, registry worktreeRegistry) error {
413		data, err := json.MarshalIndent(registry, "", "  ")
414		if err != nil {
415			return err
416		}
417		data = append(data, '\n')
418		tmp := path + ".tmp"
419		if err := os.WriteFile(tmp, data, 0o644); err != nil {
420			return err
421		}
422		return os.Rename(tmp, path)
423	}
424	
425	func ensureHeadCommit(ctx context.Context, root string, stageRegistry bool) error {
426		if headExists(ctx, root) {
427			return nil
428		}
429		if stageRegistry {
430			out, err := gitpkg.Command(ctx, root, "add", "worktrees.json").CombinedOutput()
431			if err != nil {
432				return newGitError("git add worktrees.json", out, err)
433			}
434		}
435		out, err := gitpkg.Command(
436			ctx,
437			root,
438			"-c", "user.name=DDx Bootstrap",
439			"-c", "user.email=ddx-bootstrap@localhost",
440			"-c", "commit.gpgsign=false",
441			"commit", "--allow-empty", "-m", bootstrapCommitMessage,
442		).CombinedOutput()
443		if err != nil {
444			return newGitError("git commit", out, err)
445		}
446		return nil
447	}
448	
449	func headExists(ctx context.Context, root string) bool {
450		return gitpkg.Command(ctx, root, "rev-parse", "--verify", "HEAD^{commit}").Run() == nil
451	}
452	
453	func newGitError(op string, out []byte, err error) error {
454		msg := strings.TrimSpace(string(out))
455		if msg == "" {
456			return err
457		}
458		return &gitOperationError{op: op, msg: msg, err: err}
459	}
