310	// UninstallPackage removes files recorded in the entry.
311	func UninstallPackage(entry *InstalledEntry) error {
312		var errs []string
313		for _, f := range entry.Files {
314			expanded := ExpandHome(f)
315			if err := os.Remove(expanded); err != nil && !os.IsNotExist(err) {
