// conventionPluginDir returns the plugin install directory for a project install.
// In in-tree mode (project has .ddx/), returns a relative path .ddx/plugins/<name>.
// In convention mode, returns the absolute XDG projects path for the plugin.
func conventionPluginDir(ctx context.Context, workingDir, name string) string {
	inTree := ddxroot.InTree(workingDir)
	if info, err := os.Stat(inTree); err == nil && info.IsDir() {
		// In-tree mode: keep the relative path so existing behavior is preserved
		return ddxroot.JoinRelative("plugins", name)
	}
	// Convention mode: install to the XDG projects dir
	return filepath.Join(ddxroot.Path(ctx, workingDir), "plugins", name)
}

